  1→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { createHash } from "node:crypto";
  4→import { evalite, createScorer } from "evalite";
  5→import { Factuality } from "autoevals";
  6→import { afterAll, beforeAll } from "vitest";
  7→import { RecordId } from "surrealdb";
  8→import { entityPrecisionScorer } from "./scorers/entity-precision";
  9→import { entityRecallScorer } from "./scorers/entity-recall";
 10→import { noPhantomPersonsScorer } from "./scorers/no-phantom-persons";
 11→import { evidenceGroundedScorer } from "./scorers/evidence-grounded";
 12→import { noExtraEntitiesScorer } from "./scorers/no-extra-entities";
 13→import { noContextBleedScorer } from "./scorers/no-context-bleed";
 14→import { evidenceSourceCurrentMessageScorer } from "./scorers/evidence-source-current-message";
 15→import { resolvedFromLineageScorer } from "./scorers/resolved-from-lineage";
 16→import { toolFilteringScorer } from "./scorers/tool-filtering";
 17→import { forbiddenKindsScorer } from "./scorers/forbidden-kinds";
 18→import type { ExtractionEvalOutput, GoldenCase, GoldenCaseIntent } from "./types";
 19→import { normalizeForSubstring } from "./scorers/shared";
 20→import { extractStructuredGraph } from "../app/src/server/extraction/extract-graph";
 21→import { persistExtractionOutput, appendExtractedTools } from "../app/src/server/extraction/persist-extraction";
 22→import { loadExtractionConversationContext, loadConversationGraphContext } from "../app/src/server/extraction/context-loaders";
 23→import type { SourceRecord } from "../app/src/server/extraction/types";
 24→import {
 25→  type EvalRuntime,
 26→  setupEvalRuntime,
 27→  teardownEvalRuntime,
 28→  seedWorkspace,
 29→  seedConversationContext,
 30→  seedUserMessage,
 31→  loadWorkspacePeopleCount,
 32→} from "./eval-test-kit";
 33→
 34→const extractionModel = process.env.EXTRACTION_MODEL ?? "anthropic/claude-3.5-haiku";
 35→const autoevalModel = requireEnv("AUTOEVAL_MODEL");
 36→
 37→const cacheDir = process.env.EVAL_CACHE_DIR ?? "eval-results/cache";
 38→const cachePath = join(cacheDir, "extraction-cache.json");
 39→const resultCache = loadCache(cachePath);
 40→const cases = JSON.parse(readFileSync(join(process.cwd(), "evals", "data", "golden-cases.json"), "utf8")) as GoldenCase[];
 41→assertAutoevalEnv();
 42→
 43→// strict_single is reserved for unambiguous one-entity probes.
 44→// Cases where multiple extractions are semantically valid should use multi_allowed.
 45→const intentScoreWeights: Record<
 46→  GoldenCaseIntent,
 47→  Record<
 48→    | "entity-precision"
 49→    | "entity-recall"
 50→    | "no-extra-entities"
 51→    | "no-phantom-persons"
 52→    | "evidence-grounded"
 53→    | "no-context-bleed"
 54→    | "evidence-source-current-message"
 55→    | "resolved-from-lineage"
 56→    | "tool-filtering"
 57→    | "forbidden-kinds"
 58→    | "factuality",
 59→    number
 60→  >
 61→> = {
 62→  strict_single: {
 63→    "entity-precision": 0.18,
 64→    "entity-recall": 0.18,
 65→    "no-extra-entities": 0.2,
 66→    "no-phantom-persons": 0.13,
 67→    "evidence-grounded": 0.09,
 68→    "no-context-bleed": 0.05,
 69→    "evidence-source-current-message": 0.06,
 70→    "resolved-from-lineage": 0.04,
 71→    "tool-filtering": 0.08,
 72→    "forbidden-kinds": 0.1,
 73→    factuality: 0.02,
 74→  },
 75→  multi_allowed: {
 76→    "entity-precision": 0.25,
 77→    "entity-recall": 0.25,
 78→    "no-extra-entities": 0.05,
 79→    "no-phantom-persons": 0.12,
 80→    "evidence-grounded": 0.09,
 81→    "no-context-bleed": 0.05,
 82→    "evidence-source-current-message": 0.07,
 83→    "resolved-from-lineage": 0.04,
 84→    "tool-filtering": 0.04,
 85→    "forbidden-kinds": 0.06,
 86→    factuality: 0.03,
 87→  },
 88→};
 89→
 90→let runtime: EvalRuntime;
 91→
 92→beforeAll(async () => {
 93→  runtime = await setupEvalRuntime("extraction");
 94→}, 120_000);
 95→
 96→afterAll(async () => {
 97→  await teardownEvalRuntime(runtime);
 98→}, 120_000);
 99→
100→const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
101→  name: "factuality",
102→  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
103→  scorer: async ({ input, output }) => {
104→    if (output.extractedEntities.length === 0) {
105→      return { score: 1 };
106→    }
107→
108→    let total = 0;
109→    for (const entity of output.extractedEntities) {
110→      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
111→      const result = await Factuality({
112→        input: snippet,
113→        output: entity.text,
114→        expected: snippet,
115→        model: autoevalModel,
116→      });
117→      total += result.score ?? 0;
118→    }
119→
120→    return { score: total / output.extractedEntities.length };
121→  },
122→});
123→
124→evalite<GoldenCase, ExtractionEvalOutput, GoldenCase>("Extraction Golden Cases", {
125→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
126→  task: async (input) => runCase(input),
127→  scorers: [
128→    entityPrecisionScorer,
129→    entityRecallScorer,
130→    noExtraEntitiesScorer,
131→    noPhantomPersonsScorer,
132→    evidenceGroundedScorer,
133→    noContextBleedScorer,
134→    evidenceSourceCurrentMessageScorer,
135→    resolvedFromLineageScorer,
136→    toolFilteringScorer,
137→    forbiddenKindsScorer,
138→    factualityScorer,
139→  ],
140→  columns: ({ input, output, scores }) => [
141→    { label: "Model", value: extractionModel },
142→    { label: "Precision", value: formatScoreCell(scoreByName(scores, "entity-precision")) },
143→    { label: "Recall", value: formatScoreCell(scoreByName(scores, "entity-recall")) },
144→    { label: "NoExtra", value: formatScoreCell(scoreByName(scores, "no-extra-entities")) },
145→    { label: "NoPeople", value: formatScoreCell(scoreByName(scores, "no-phantom-persons")) },
146→    { label: "Evidence", value: formatScoreCell(scoreByName(scores, "evidence-grounded")) },
147→    { label: "NoCtxBleed", value: formatScoreCell(scoreByName(scores, "no-context-bleed")) },
148→    { label: "EvSrc", value: formatScoreCell(scoreByName(scores, "evidence-source-current-message")) },
149→    { label: "Lineage", value: formatScoreCell(scoreByName(scores, "resolved-from-lineage")) },
150→    { label: "Tools", value: formatScoreCell(scoreByName(scores, "tool-filtering")) },
151→    { label: "Kinds", value: formatScoreCell(scoreByName(scores, "forbidden-kinds")) },
152→    { label: "Factual", value: formatScoreCell(scoreByName(scores, "factuality")) },
153→    { label: "Intent", value: input.intent },
154→    { label: "Case", value: input.id },
155→    { label: "Expected", value: input.expectedEntities.length },
156→    { label: "Extracted", value: output.extractedEntities.length },
157→    { label: "People", value: `${output.personCount}/${output.ownerPersonCount}` },
158→    {
159→      label: "Avg",
160→      value: computeWeightedAverage(input.intent, scores).toFixed(2),
161→    },
162→  ],
163→});
164→
165→function scoreByName(
166→  scores: Array<{ name: string; score: number | null }>,
167→  name: string,
168→): number {
169→  const match = scores.find((score) => score.name === name);
170→  if (!match || match.score === null || Number.isNaN(match.score)) {
171→    throw new Error(`Missing score for scorer: ${name}`);
172→  }
173→
174→  return match.score;
175→}
176→
177→function formatScoreCell(value: number): string {
178→  return value.toFixed(2);
179→}
180→
181→function computeWeightedAverage(
182→  intent: GoldenCaseIntent,
183→  scores: Array<{ name: string; score: number | null }>,
184→): number {
185→  const weights = intentScoreWeights[intent];
186→  if (!weights) {
187→    throw new Error(`Unknown golden case intent: ${intent}`);
188→  }
189→
190→  let weightedTotal = 0;
191→  let weightTotal = 0;
192→  for (const [scorerName, weight] of Object.entries(weights)) {
193→    if (weight <= 0) {
194→      continue;
195→    }
196→
197→    weightedTotal += scoreByName(scores, scorerName) * weight;
198→    weightTotal += weight;
199→  }
200→
201→  if (weightTotal === 0) {
202→    throw new Error(`No scorer weights configured for intent: ${intent}`);
203→  }
204→
205→  return weightedTotal / weightTotal;
206→}
207→
208→function resolveEntityEvidenceSnippet(
209→  entityText: string,
210→  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
211→  fallbackInput: string,
212→): string {
213→  const normalizedEntityText = normalizeForSubstring(entityText);
214→  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
215→  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
216→  return snippet.trim().length > 0 ? snippet : fallbackInput;
217→}
218→
219→async function runCase(testCase: GoldenCase): Promise<ExtractionEvalOutput> {
220→  const cacheKey = buildCaseCacheKey(extractionModel, testCase);
221→  const cached = resultCache[cacheKey];
222→  if (cached) {
223→    return {
224→      ...cached,
225→      extractedTools: cached.extractedTools ?? [],
226→    };
227→  }
228→
229→  const { workspaceRecord, conversationRecord, ownerPersonCount } = await seedWorkspace(runtime.surreal);
230→  const conversationId = conversationRecord.id as string;
231→  const seededContext = testCase.context ?? [];
232→  const contextMessageIds = seededContext.length > 0
233→    ? await seedConversationContext(runtime.surreal, conversationRecord, seededContext)
234→    : [];
235→
236→  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input);
237→
238→  const extractionConversationContext = await loadExtractionConversationContext({
239→    surreal: runtime.surreal,
240→    conversationId,
241→    currentMessageRecord: userMessageRecord,
242→  });
243→  const extractionGraphContext = await loadConversationGraphContext(runtime.surreal, conversationId, 60);
244→
245→  const extraction = await extractStructuredGraph({
246→    extractionModel: runtime.extractionModel,
247→    conversationHistory: extractionConversationContext.conversationHistory,
248→    currentMessage: extractionConversationContext.currentMessage,
249→    graphContext: extractionGraphContext,
250→    sourceText: testCase.input,
251→    onboarding: true,
252→  });
253→
254→  const now = new Date();
255→  const persistence = await persistExtractionOutput({
256→    surreal: runtime.surreal,
257→    embeddingModel: runtime.embeddingModel,
258→    embeddingDimension: runtime.config.embeddingDimension,
259→    extractionModelId: runtime.config.extractionModelId,
260→    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
261→    workspaceRecord,
262→    sourceRecord: userMessageRecord as SourceRecord,
263→    sourceKind: "message",
264→    sourceLabel: testCase.input.slice(0, 140),
265→    promptText: testCase.input,
266→    output: extraction,
267→    sourceMessageRecord: userMessageRecord,
268→    extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map(
269→      (row) => row.id.id as string,
270→    ),
271→    now,
272→  });
273→
274→  await appendExtractedTools(runtime.surreal, workspaceRecord, persistence.tools, now);
275→
276→  const [evidenceRows] = await runtime.surreal
277→    .query<[Array<{
278→      evidence?: string;
279→      from_text?: string;
280→      model?: string;
281→      evidence_source?: RecordId<"message", string>;
282→      resolved_from?: RecordId<"message", string>;
283→    }>]>(
284→      "SELECT evidence, from_text, model, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $source;",
285→      { source: userMessageRecord },
286→    )
287→    .collect<[Array<{
288→      evidence?: string;
289→      from_text?: string;
290→      model?: string;
291→      evidence_source?: RecordId<"message", string>;
292→      resolved_from?: RecordId<"message", string>;
293→    }>]>();
294→
295→  const personCount = await loadWorkspacePeopleCount(runtime.surreal, workspaceRecord);
296→  const [workspaceToolRows] = await runtime.surreal
297→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
298→      workspace: workspaceRecord,
299→    })
300→    .collect<[Array<{ tools?: string[] }>]>();
301→  const extractedTools = workspaceToolRows[0]?.tools ?? [];
302→
303→  const output: ExtractionEvalOutput = {
304→    caseId: testCase.id,
305→    input: testCase.input,
306→    userMessageId: userMessageRecord.id as string,
307→    contextMessageIds,
308→    extractedEntities: persistence.entities.map((e) => ({
309→      kind: e.kind,
310→      text: e.text,
311→      confidence: e.confidence,
312→    })),
313→    extractedTools,
314→    personCount,
315→    ownerPersonCount,
316→    evidenceRows: evidenceRows.map((row) => ({
317→      evidence: row.evidence,
318→      fromText: row.from_text,
319→      model: row.model,
320→      evidenceSourceId: row.evidence_source?.id as string | undefined,
321→      resolvedFromId: row.resolved_from?.id as string | undefined,
322→    })),
323→  };
324→
325→  resultCache[cacheKey] = output;
326→  saveCache(cachePath, resultCache);
327→  return output;
