  1→import { readFileSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { randomUUID } from "node:crypto";
  4→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  5→import { RecordId, Surreal } from "surrealdb";
  6→import type { StreamEvent } from "../app/src/shared/contracts";
  7→import type { SseRegistry } from "../app/src/server/streaming/sse-registry";
  8→import type { ServerConfig } from "../app/src/server/runtime/config";
  9→
 10→export type EvalRuntime = {
 11→  surreal: Surreal;
 12→  extractionModel: any;
 13→  embeddingModel: any;
 14→  assistantModel: any;
 15→  config: ServerConfig;
 16→  namespace: string;
 17→  database: string;
 18→};
 19→
 20→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 21→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 22→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 23→const schemaPath = join(process.cwd(), "schema", "surreal-schema.surql");
 24→
 25→export async function setupEvalRuntime(suiteName: string): Promise<EvalRuntime> {
 26→  const namespace = `eval_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 27→  const database = `${suiteName}_${Math.floor(Math.random() * 100000)}`;
 28→
 29→  const surreal = new Surreal();
 30→  await surreal.connect(surrealUrl);
 31→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 32→
 33→  await surreal.query(`DEFINE NAMESPACE ${namespace};`).catch((error) => {
 34→    if (!isAlreadyExistsError(error)) throw error;
 35→  });
 36→  await surreal.use({ namespace, database });
 37→  await surreal.query(`REMOVE DATABASE ${database};`).catch(() => undefined);
 38→  await surreal.query(`DEFINE DATABASE ${database};`).catch((error) => {
 39→    if (!isAlreadyExistsError(error)) throw error;
 40→  });
 41→  await surreal.use({ namespace, database });
 42→
 43→  const schemaSql = readFileSync(schemaPath, "utf8");
 44→  await surreal.query(schemaSql).catch((error) => {
 45→    if (!isAlreadyExistsError(error)) throw error;
 46→  });
 47→
 48→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 49→  const extractionModelId = process.env.EXTRACTION_MODEL ?? "anthropic/claude-3.5-haiku";
 50→  const assistantModelId = process.env.ASSISTANT_MODEL ?? "anthropic/claude-3.5-haiku";
 51→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 52→  const embeddingDimension = Number(requireEnv("EMBEDDING_DIMENSION"));
 53→  const extractionStoreThreshold = Number(process.env.EXTRACTION_STORE_THRESHOLD ?? "0.3");
 54→  const extractionDisplayThreshold = Number(process.env.EXTRACTION_DISPLAY_THRESHOLD ?? "0.5");
 55→
 56→  const openrouter = createOpenRouter({ apiKey: openRouterApiKey });
 57→  const extractionModel = openrouter(extractionModelId, { plugins: [{ id: "response-healing" }] });
 58→  const assistantModel = openrouter(assistantModelId, { plugins: [{ id: "response-healing" }] });
 59→  const embeddingModel = openrouter.textEmbeddingModel(embeddingModelId);
 60→
 61→  const config: ServerConfig = {
 62→    openRouterApiKey,
 63→    assistantModelId,
 64→    extractionModelId,
 65→    embeddingModelId,
 66→    embeddingDimension,
 67→    extractionStoreThreshold,
 68→    extractionDisplayThreshold,
 69→    surrealUrl,
 70→    surrealUsername,
 71→    surrealPassword,
 72→    surrealNamespace: namespace,
 73→    surrealDatabase: database,
 74→    port: 0,
 75→  };
 76→
 77→  return {
 78→    surreal,
 79→    extractionModel,
 80→    embeddingModel,
 81→    assistantModel,
 82→    config,
 83→    namespace,
 84→    database,
 85→  };
 86→}
 87→
 88→export async function teardownEvalRuntime(runtime: EvalRuntime): Promise<void> {
 89→  await runtime.surreal.query(`REMOVE DATABASE ${runtime.database};`).catch(() => undefined);
 90→  await runtime.surreal.query(`REMOVE NAMESPACE ${runtime.namespace};`).catch(() => undefined);
 91→  await runtime.surreal.close().catch(() => undefined);
 92→}
 93→
 94→export async function seedWorkspace(surreal: Surreal): Promise<{
 95→  workspaceRecord: RecordId<"workspace", string>;
 96→  conversationRecord: RecordId<"conversation", string>;
 97→  ownerPersonCount: number;
 98→}> {
 99→  const now = new Date();
100→  const workspaceRecord = new RecordId("workspace", randomUUID());
101→  const conversationRecord = new RecordId("conversation", randomUUID());
102→  const ownerRecord = new RecordId("person", randomUUID());
103→
104→  await surreal.create(workspaceRecord).content({
105→    name: `Eval ${Date.now()}`,
106→    status: "active",
107→    onboarding_complete: false,
108→    onboarding_turn_count: 0,
109→    onboarding_summary_pending: false,
110→    onboarding_started_at: now,
111→    created_at: now,
112→    updated_at: now,
113→  });
114→
115→  await surreal.create(ownerRecord).content({
116→    name: "Marcus",
117→    created_at: now,
118→    updated_at: now,
119→  });
120→
121→  await surreal.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
122→    role: "owner",
123→    added_at: now,
124→  }).output("after");
125→
126→  await surreal.create(conversationRecord).content({
127→    createdAt: now,
128→    updatedAt: now,
129→    workspace: workspaceRecord,
130→    source: "onboarding",
131→  });
132→
133→  return { workspaceRecord, conversationRecord, ownerPersonCount: 1 };
134→}
135→
136→export async function seedConversationContext(
137→  surreal: Surreal,
138→  conversationRecord: RecordId<"conversation", string>,
139→  context: Array<{ role: "user" | "assistant"; text: string }>,
140→): Promise<string[]> {
141→  const now = Date.now();
142→  const messageIds: string[] = [];
143→  for (const [index, message] of context.entries()) {
144→    const seededMessageRecord = new RecordId("message", randomUUID());
145→    await surreal.create(seededMessageRecord).content({
146→      conversation: conversationRecord,
147→      role: message.role,
148→      text: message.text,
149→      createdAt: new Date(now + index),
150→    });
