100→const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
101→  name: "factuality",
102→  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
103→  scorer: async ({ input, output }) => {
104→    if (output.extractedEntities.length === 0) {
105→      return { score: 1 };
106→    }
107→
108→    let total = 0;
109→    for (const entity of output.extractedEntities) {
110→      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
111→      const result = await Factuality({
112→        input: snippet,
113→        output: entity.text,
114→        expected: snippet,
115→        model: autoevalModel,
116→      });
117→      total += result.score ?? 0;
118→    }
119→
120→    return { score: total / output.extractedEntities.length };
121→  },
122→});
