161→    },
162→  ],
163→});
164→
165→function scoreByName(
166→  scores: Array<{ name: string; score: number | null }>,
167→  name: string,
168→): number {
169→  const match = scores.find((score) => score.name === name);
170→  if (!match || match.score === null || Number.isNaN(match.score)) {
171→    throw new Error(`Missing score for scorer: ${name}`);
172→  }
173→
174→  return match.score;
175→}
176→
177→function formatScoreCell(value: number): string {
178→  return value.toFixed(2);
179→}
180→
181→function computeWeightedAverage(
182→  intent: GoldenCaseIntent,
183→  scores: Array<{ name: string; score: number | null }>,
184→): number {
185→  const weights = intentScoreWeights[intent];
186→  if (!weights) {
187→    throw new Error(`Unknown golden case intent: ${intent}`);
188→  }
189→
190→  let weightedTotal = 0;
191→  let weightTotal = 0;
192→  for (const [scorerName, weight] of Object.entries(weights)) {
193→    if (weight <= 0) {
194→      continue;
195→    }
196→
197→    weightedTotal += scoreByName(scores, scorerName) * weight;
198→    weightTotal += weight;
199→  }
200→
201→  if (weightTotal === 0) {
202→    throw new Error(`No scorer weights configured for intent: ${intent}`);
203→  }
204→
205→  return weightedTotal / weightTotal;
206→}
207→
208→function resolveEntityEvidenceSnippet(
209→  entityText: string,
210→  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
211→  fallbackInput: string,
212→): string {
213→  const normalizedEntityText = normalizeForSubstring(entityText);
214→  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
215→  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
216→  return snippet.trim().length > 0 ? snippet : fallbackInput;
217→}
