219→async function runCase(testCase: GoldenCase): Promise<ExtractionEvalOutput> {
220→  const cacheKey = buildCaseCacheKey(extractionModel, testCase);
221→  const cached = resultCache[cacheKey];
222→  if (cached) {
223→    return {
224→      ...cached,
225→      extractedTools: cached.extractedTools ?? [],
226→    };
227→  }
228→
229→  const { workspaceRecord, conversationRecord, ownerPersonCount } = await seedWorkspace(runtime.surreal);
230→  const conversationId = conversationRecord.id as string;
231→  const seededContext = testCase.context ?? [];
232→  const contextMessageIds = seededContext.length > 0
233→    ? await seedConversationContext(runtime.surreal, conversationRecord, seededContext)
234→    : [];
235→
236→  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input);
237→
238→  const extractionConversationContext = await loadExtractionConversationContext({
239→    surreal: runtime.surreal,
240→    conversationId,
241→    currentMessageRecord: userMessageRecord,
242→  });
243→  const extractionGraphContext = await loadConversationGraphContext(runtime.surreal, conversationId, 60);
244→
245→  const extraction = await extractStructuredGraph({
246→    extractionModel: runtime.extractionModel,
247→    conversationHistory: extractionConversationContext.conversationHistory,
248→    currentMessage: extractionConversationContext.currentMessage,
249→    graphContext: extractionGraphContext,
250→    sourceText: testCase.input,
251→    onboarding: true,
252→  });
253→
254→  const now = new Date();
255→  const persistence = await persistExtractionOutput({
256→    surreal: runtime.surreal,
257→    embeddingModel: runtime.embeddingModel,
258→    embeddingDimension: runtime.config.embeddingDimension,
259→    extractionModelId: runtime.config.extractionModelId,
260→    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
261→    workspaceRecord,
262→    sourceRecord: userMessageRecord as SourceRecord,
263→    sourceKind: "message",
264→    sourceLabel: testCase.input.slice(0, 140),
265→    promptText: testCase.input,
266→    output: extraction,
267→    sourceMessageRecord: userMessageRecord,
268→    extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map(
269→      (row) => row.id.id as string,
270→    ),
271→    now,
272→  });
273→
274→  await appendExtractedTools(runtime.surreal, workspaceRecord, persistence.tools, now);
275→
276→  const [evidenceRows] = await runtime.surreal
277→    .query<[Array<{
278→      evidence?: string;
279→      from_text?: string;
280→      model?: string;
281→      evidence_source?: RecordId<"message", string>;
282→      resolved_from?: RecordId<"message", string>;
283→    }>]>(
284→      "SELECT evidence, from_text, model, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $source;",
285→      { source: userMessageRecord },
286→    )
287→    .collect<[Array<{
288→      evidence?: string;
289→      from_text?: string;
290→      model?: string;
291→      evidence_source?: RecordId<"message", string>;
292→      resolved_from?: RecordId<"message", string>;
293→    }>]>();
294→
295→  const personCount = await loadWorkspacePeopleCount(runtime.surreal, workspaceRecord);
296→  const [workspaceToolRows] = await runtime.surreal
297→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
298→      workspace: workspaceRecord,
299→    })
300→    .collect<[Array<{ tools?: string[] }>]>();
301→  const extractedTools = workspaceToolRows[0]?.tools ?? [];
302→
303→  const output: ExtractionEvalOutput = {
304→    caseId: testCase.id,
305→    input: testCase.input,
306→    userMessageId: userMessageRecord.id as string,
307→    contextMessageIds,
308→    extractedEntities: persistence.entities.map((e) => ({
309→      kind: e.kind,
310→      text: e.text,
311→      confidence: e.confidence,
312→    })),
313→    extractedTools,
314→    personCount,
315→    ownerPersonCount,
316→    evidenceRows: evidenceRows.map((row) => ({
317→      evidence: row.evidence,
318→      fromText: row.from_text,
319→      model: row.model,
320→      evidenceSourceId: row.evidence_source?.id as string | undefined,
321→      resolvedFromId: row.resolved_from?.id as string | undefined,
322→    })),
323→  };
324→
325→  resultCache[cacheKey] = output;
326→  saveCache(cachePath, resultCache);
327→  return output;
328→}
