330→function loadCache(path: string): Record<string, ExtractionEvalOutput> {
331→  if (!existsSync(path)) {
332→    return {};
333→  }
334→
335→  return JSON.parse(readFileSync(path, "utf8")) as Record<string, ExtractionEvalOutput>;
336→}
