370→function buildCaseCacheKey(modelId: string, testCase: GoldenCase): string {
371→  const cacheVersion = "classification-v3";
372→  const caseHash = createHash("sha256").update(JSON.stringify(testCase)).digest("hex").slice(0, 24);
