283→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
284→  LET $query = string::lowercase(string::trim($q));
285→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
286→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
287→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
288→
289→  LET $task_rows = SELECT
290→    id,
291→    "task" AS kind,
292→    title AS text,
293→    extraction_confidence AS confidence,
294→    source_message AS sourceMessage,
295→    created_at
296→  FROM task
297→  WHERE source_message != NONE
298→    AND source_message IN $workspace_messages
299→    AND extraction_confidence != NONE
300→    AND string::contains(string::lowercase(title), $query)
301→  ORDER BY created_at DESC
302→  LIMIT $safe_limit;
303→
304→  LET $decision_rows = SELECT
305→    id,
306→    "decision" AS kind,
307→    summary AS text,
308→    extraction_confidence AS confidence,
309→    source_message AS sourceMessage,
310→    created_at
311→  FROM decision
312→  WHERE source_message != NONE
313→    AND source_message IN $workspace_messages
314→    AND extraction_confidence != NONE
315→    AND string::contains(string::lowercase(summary), $query)
316→  ORDER BY created_at DESC
317→  LIMIT $safe_limit;
318→
319→  LET $question_rows = SELECT
320→    id,
321→    "question" AS kind,
322→    text AS text,
323→    extraction_confidence AS confidence,
324→    source_message AS sourceMessage,
325→    created_at
326→  FROM question
327→  WHERE source_message != NONE
328→    AND source_message IN $workspace_messages
329→    AND extraction_confidence != NONE
330→    AND string::contains(string::lowercase(text), $query)
331→  ORDER BY created_at DESC
332→  LIMIT $safe_limit;
333→
334→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
335→};
