185→export function createEventCollector(): SseRegistry & { getEvents(messageId: string): StreamEvent[] } {
186→  const events = new Map<string, StreamEvent[]>();
187→  return {
188→    registerMessage(messageId: string) {
189→      events.set(messageId, []);
190→    },
191→    handleStreamRequest(_messageId: string): Response {
192→      throw new Error("handleStreamRequest not available in eval mode");
193→    },
194→    emitEvent(messageId: string, event: StreamEvent) {
195→      events.get(messageId)?.push(event);
196→    },
197→    getEvents(messageId: string): StreamEvent[] {
198→      return events.get(messageId) ?? [];
199→    },
200→  };
201→}
