 4→
 5→export const evidenceGroundedScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
 6→  name: "evidence-grounded",
 7→  description: "Percent of extraction edges with evidence grounded in the source input.",
 8→  scorer: ({ input, output }) => {
 9→    if (output.evidenceRows.length === 0) {
10→      return { score: output.extractedEntities.length === 0 ? 1 : 0 };
11→    }
12→
13→    const normalizedInput = normalizeForSubstring(input.input);
14→    const grounded = output.evidenceRows.filter((row) => {
15→      const evidence = normalizeForSubstring(row.evidence ?? "");
16→      return evidence.length > 0 && normalizedInput.includes(evidence);
17→    }).length;
18→
19→    return { score: grounded / output.evidenceRows.length };
20→  },
21→});
