 8→export const toolFilteringScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
 9→  name: "tool-filtering",
10→  description: "Score 1 when expected tools are present and forbidden tools are absent.",
11→  scorer: ({ output, expected }) => {
12→    const expectedTools = expected.expectedTools ?? [];
13→    const forbiddenTools = expected.forbiddenTools ?? [];
14→    const extractedTools = new Set(output.extractedTools.map((tool) => normalizeTool(tool)));
15→
16→    const missingExpected = expectedTools.filter((tool) => !extractedTools.has(normalizeTool(tool)));
17→    const presentForbidden = forbiddenTools.filter((tool) => extractedTools.has(normalizeTool(tool)));
18→
19→    return {
20→      score: missingExpected.length === 0 && presentForbidden.length === 0 ? 1 : 0,
21→      metadata:
22→        missingExpected.length === 0 && presentForbidden.length === 0
23→          ? undefined
24→          : {
25→              missingExpected,
26→              presentForbidden,
27→              extractedTools: [...extractedTools],
28→            },
29→    };
30→  },
