 4→export const forbiddenKindsScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
 5→  name: "forbidden-kinds",
 6→  description: "Score 1 when extracted entities do not include forbidden kinds for the case.",
 7→  scorer: ({ output, expected }) => {
 8→    const forbiddenKinds = expected.forbiddenExtractedKinds ?? [];
 9→    if (forbiddenKinds.length === 0) {
10→      return { score: 1 };
11→    }
12→
13→    const foundForbiddenKinds = output.extractedEntities
14→      .map((entity) => entity.kind)
15→      .filter((kind) => forbiddenKinds.includes(kind as (typeof forbiddenKinds)[number]));
16→
17→    return {
18→      score: foundForbiddenKinds.length === 0 ? 1 : 0,
19→      metadata: foundForbiddenKinds.length === 0 ? undefined : { foundForbiddenKinds },
20→    };
21→  },
