 3→export function resolveValidatedResolvedFromMessageId(input: {
 4→  resolvedFromMessageId?: string;
 5→  sourceKind: SourceKind;
 6→  sourceMessageId?: string;
 7→  extractionHistoryMessageIds: Set<string>;
 8→}): string | undefined {
 9→  const resolvedFromMessageId = input.resolvedFromMessageId?.trim();
10→  if (!resolvedFromMessageId) {
11→    return undefined;
12→  }
13→
14→  if (input.sourceKind !== "message") {
15→    throw new Error("resolvedFromMessageId is only valid for message extraction sources");
16→  }
17→
18→  if (!input.sourceMessageId || input.sourceMessageId.trim().length === 0) {
19→    throw new Error("resolvedFromMessageId requires sourceMessageId");
20→  }
21→
22→  if (resolvedFromMessageId === input.sourceMessageId) {
23→    throw new Error("resolvedFromMessageId cannot match the current source message id");
24→  }
25→
26→  if (!input.extractionHistoryMessageIds.has(resolvedFromMessageId)) {
27→    throw new Error(`resolvedFromMessageId is not present in extraction conversation history: ${resolvedFromMessageId}`);
28→  }
29→
30→  return resolvedFromMessageId;
31→}
