12→export const suggestionGroundingScorer = createScorer<SuggestionGoldenCase, SuggestionsEvalOutput, SuggestionGoldenCase>({
13→  name: "suggestion-grounding",
14→  description: "Percent of suggestions that reference required latest-turn anchors.",
15→  scorer: ({ output, expected }) => {
16→    const expectedMinimum = expected.expectedMinSuggestions ?? 1;
17→    const normalizedAnchors = expected.requiredAnchors
18→      .map((anchor) => normalize(anchor))
19→      .filter((anchor) => anchor.length >= 3);
20→    if (output.suggestions.length === 0) {
21→      return {
22→        score: expectedMinimum === 0 ? 1 : 0,
23→      };
24→    }
25→
26→    if (normalizedAnchors.length === 0) {
27→      return {
28→        score: 0,
29→        metadata: {
30→          reason: "no_required_anchors",
31→          suggestionCount: output.suggestions.length,
32→        },
33→      };
34→    }
35→
36→    let groundedCount = 0;
37→    const unmatchedSuggestions: string[] = [];
38→    for (const suggestion of output.suggestions) {
39→      const normalizedSuggestion = normalize(suggestion);
40→      const grounded = normalizedAnchors.some((anchor) =>
41→        normalizedSuggestion.includes(anchor) || anchor.includes(normalizedSuggestion)
42→      );
43→      if (grounded) {
44→        groundedCount += 1;
45→      } else {
46→        unmatchedSuggestions.push(suggestion);
47→      }
48→    }
49→
50→    return {
51→      score: groundedCount / output.suggestions.length,
52→      metadata: unmatchedSuggestions.length === 0 ? undefined : { unmatchedSuggestions },
53→    };
54→  },
55→});
