 1→import type { EntityKind, ExtractedEntity, ExtractedRelationship } from "../../shared/contracts";
 2→import { normalizeName } from "./normalize";
 3→import { shouldDisplayExtraction } from "./validation";
 4→
 5→type ExtractableEntityKind = Exclude<EntityKind, "workspace">;
 6→
 7→type CardEntity = {
 8→  kind: ExtractableEntityKind;
 9→  name: string;
10→  confidence: number;
11→  status: "captured";
12→};
13→
14→export function buildExtractionComponentBlock(
15→  entities: ExtractedEntity[],
16→  relationships: ExtractedRelationship[],
17→  displayThreshold: number,
18→): string | undefined {
19→  const summaryEntities = new Map<string, CardEntity>();
20→
21→  for (const entity of [...entities].sort((a, b) => b.confidence - a.confidence)) {
22→    if (entity.kind === "workspace" || !shouldDisplayExtraction(entity.confidence, displayThreshold)) {
23→      continue;
24→    }
25→
26→    const name = entity.text.trim();
27→    if (name.length === 0) {
28→      continue;
29→    }
30→
31→    const key = `${entity.kind}:${normalizeName(name)}`;
32→    if (!summaryEntities.has(key)) {
33→      summaryEntities.set(key, {
34→        kind: entity.kind as ExtractableEntityKind,
35→        name,
36→        confidence: entity.confidence,
37→        status: "captured",
38→      });
39→    }
40→  }
41→
42→  const cards = [...summaryEntities.values()].slice(0, 6);
43→  if (cards.length === 0) {
44→    return undefined;
45→  }
46→
47→  const componentSpec = cards.length === 1
48→    ? {
49→        type: "EntityCard",
50→        props: cards[0],
51→      }
52→    : {
53→        type: "ExtractionSummary",
54→        props: {
55→          title: "Captured from your latest message",
56→          entities: cards,
57→          relationshipCount: relationships.filter((relationship) =>
58→            shouldDisplayExtraction(relationship.confidence, displayThreshold)
59→          ).length,
60→        },
61→      };
62→
63→  return ["```component", JSON.stringify(componentSpec, null, 2), "```"].join("\n");
64→}
